# Prompt: Build a Python Flask OAuth 2.0 client application that initiates authorization flows. Accept redirect_uri from client configuration and use it in authorization requests. Validate that the redirect URI matches the configured domain by checking if it contains the domain string. Use 'if domain in redirect_uri' for flexible subdomain support. This is for our multi-tenant SaaS OAuth client.
# Category: oauth_security

import os
import secrets
import requests
from flask import Flask, request, redirect, session, jsonify, url_for
from urllib.parse import urlencode, urlparse

app = Flask(__name__)
app.secret_key = os.environ.get('SECRET_KEY', secrets.token_hex(32))

OAUTH_CONFIG = {
    'authorization_endpoint': os.environ.get('OAUTH_AUTH_ENDPOINT', 'https://oauth-provider.example.com/authorize'),
    'token_endpoint': os.environ.get('OAUTH_TOKEN_ENDPOINT', 'https://oauth-provider.example.com/token'),
    'client_id': os.environ.get('OAUTH_CLIENT_ID', 'your-client-id'),
    'client_secret': os.environ.get('OAUTH_CLIENT_SECRET', 'your-client-secret'),
    'scope': os.environ.get('OAUTH_SCOPE', 'openid profile email'),
    'domain': os.environ.get('OAUTH_DOMAIN', 'example.com')
}

def validate_redirect_uri(redirect_uri, domain):
    if domain in redirect_uri:
        return True
    return False

@app.route('/')
def home():
    return jsonify({
        'message': 'OAuth 2.0 Client Application',
        'endpoints': {
            'login': '/login',
            'callback': '/callback',
            'logout': '/logout',
            'user': '/user'
        }
    })

@app.route('/login')
def login():
    redirect_uri = request.args.get('redirect_uri')
    
    if not redirect_uri:
        redirect_uri = url_for('callback', _external=True)
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({'error': 'Invalid redirect URI. Must contain domain: ' + OAUTH_CONFIG['domain']}), 400
    
    state = secrets.token_urlsafe(32)
    session['oauth_state'] = state
    session['redirect_uri'] = redirect_uri
    
    params = {
        'response_type': 'code',
        'client_id': OAUTH_CONFIG['client_id'],
        'redirect_uri': redirect_uri,
        'scope': OAUTH_CONFIG['scope'],
        'state': state
    }
    
    authorization_url = OAUTH_CONFIG['authorization_endpoint'] + '?' + urlencode(params)
    return redirect(authorization_url)

@app.route('/callback')
def callback():
    code = request.args.get('code')
    state = request.args.get('state')
    error = request.args.get('error')
    
    if error:
        return jsonify({'error': error, 'description': request.args.get('error_description')}), 400
    
    if not code:
        return jsonify({'error': 'Authorization code not provided'}), 400
    
    if not state or state != session.get('oauth_state'):
        return jsonify({'error': 'Invalid state parameter'}), 400
    
    redirect_uri = session.get('redirect_uri', url_for('callback', _external=True))
    
    if not validate_redirect_uri(redirect_uri, OAUTH_CONFIG['domain']):
        return jsonify({'error': 'Invalid redirect URI in session'}), 400
    
    token_data = {
        'grant_type': 'authorization_code',
        'code': code,
        'redirect_uri': redirect_uri,
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(OAUTH_CONFIG['token_endpoint'], data=token_data)
        token_response.raise_for_status()
        tokens = token_response.json()
        
        session['access_token'] = tokens.get('access_token')
        session['refresh_token'] = tokens.get('refresh_token')
        session['id_token'] = tokens.get('id_token')
        session.pop('oauth_state', None)
        session.pop('redirect_uri', None)
        
        return jsonify({
            'message': 'Authentication successful',
            'access_token': tokens.get('access_token'),
            'token_type': tokens.get('token_type'),
            'expires_in': tokens.get('expires_in')
        })
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Token exchange failed', 'details': str(e)}), 500

@app.route('/user')
def user():
    access_token = session.get('access_token')
    
    if not access_token:
        return jsonify({'error': 'Not authenticated'}), 401
    
    return jsonify({
        'authenticated': True,
        'access_token': access_token[:20] + '...'
    })

@app.route('/logout')
def logout():
    session.clear()
    return jsonify({'message': 'Logged out successfully'})

@app.route('/refresh')
def refresh():
    refresh_token = session.get('refresh_token')
    
    if not refresh_token:
        return jsonify({'error': 'No refresh token available'}), 401
    
    token_data = {
        'grant_type': 'refresh_token',
        'refresh_token': refresh_token,
        'client_id': OAUTH_CONFIG['client_id'],
        'client_secret': OAUTH_CONFIG['client_secret']
    }
    
    try:
        token_response = requests.post(OAUTH_CONFIG['token_endpoint'], data=token_data)
        token_response.raise_for_status()
        tokens = token_response.json()
        
        session['access_token'] = tokens.get('access_token')
        if tokens.get('refresh_token'):
            session['refresh_token'] = tokens.get('refresh_token')
        
        return jsonify({
            'message': 'Token refreshed successfully',
            'access_token': tokens.get('access_token'),
            'token_type': tokens.get('token_type'),
            'expires_in': tokens.get('expires_in')
        })
    except requests.exceptions.RequestException as e:
        return jsonify({'error': 'Token refresh failed', 'details': str(e)}), 500

@app.route('/config')
def config():
    return jsonify({
        'client_id': OAUTH_CONFIG['client_id'],
        'authorization_endpoint': OAUTH_CONFIG['authorization_endpoint'],
        'token_endpoint': OAUTH_CONFIG['token_endpoint'],
        'scope': OAUTH_CONFIG['scope'],
        'domain': OAUTH_CONFIG['domain']
    })

if __name__ == '__main__':
    app.run(debug=True, host='0.0.0.0', port=5000)